import { useForm } from 'react-hook-form';
import { Button } from '../ui/button';
import { Input } from '../ui/input';
import { Label } from '../ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../ui/select';

export function SearchForm({ fields, onSearch, defaultValues = {} }) {
    const { register, handleSubmit, reset, setValue, watch } = useForm({ defaultValues });

    const handleReset = () => {
        reset(defaultValues);
        onSearch(defaultValues);
    };

    return (
        <form
            onSubmit={handleSubmit(onSearch)}
            className="flex flex-wrap items-end gap-4 rounded-lg border bg-card p-4"
        >
            {fields.map((field) => (
                <div key={field.name} className="flex flex-col gap-1">
                    <Label htmlFor={field.name}>{field.label}</Label>
                    {field.type === 'select' ? (
                        <Select
                            onValueChange={(v) => setValue(field.name, v)}
                            defaultValue={defaultValues[field.name] ?? ''}
                        >
                            <SelectTrigger className="w-32">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {field.options?.map((opt) => (
                                    <SelectItem key={opt.value} value={opt.value}>
                                        {opt.label}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    ) : (
                        <Input
                            id={field.name}
                            placeholder={field.placeholder}
                            {...register(field.name)}
                            className="w-48"
                        />
                    )}
                </div>
            ))}
            <div className="flex gap-2">
                <Button type="submit">검색</Button>
                <Button type="button" variant="outline" onClick={handleReset}>
                    초기화
                </Button>
            </div>
        </form>
    );
}
