import { useRef, useState } from 'react';
import { Upload } from 'lucide-react';
import { cn } from '../../utils/cn';

export function FileUpload({ onFileSelect, accept, className }) {
    const inputRef = useRef(null);
    const [isDragging, setIsDragging] = useState(false);

    const handleChange = (e) => {
        const file = e.target.files?.[0];
        if (file) onFileSelect(file);
    };

    const handleDrop = (e) => {
        e.preventDefault();
        setIsDragging(false);
        const file = e.dataTransfer.files?.[0];
        if (file) onFileSelect(file);
    };

    return (
        <div
            onClick={() => inputRef.current?.click()}
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleDrop}
            className={cn(
                'flex cursor-pointer flex-col items-center justify-center rounded-lg border-2 border-dashed p-8 text-muted-foreground transition-colors hover:border-primary hover:text-primary',
                isDragging && 'border-primary bg-primary/5',
                className
            )}
        >
            <Upload className="mb-2 h-8 w-8" />
            <p className="text-sm">파일을 선택하거나 드래그하여 업로드</p>
            {accept && <p className="mt-1 text-xs">{accept} 형식 지원</p>}
            <input
                ref={inputRef}
                type="file"
                accept={accept}
                className="hidden"
                onChange={handleChange}
            />
        </div>
    );
}
